const html = $input.first().json.data;
const PROXY = 'https://kokolsk1y.app.n8n.cloud/webhook/tv-video?url=';

function proxyUrl(url) {
  if (!url) return '';
  return PROXY + encodeURIComponent(url);
}

const msgPattern = /data-post="electrocentre39\/(\d+)"/g;
const msgIds = [];
let match;
while ((match = msgPattern.exec(html)) !== null) {
  msgIds.push(match[1]);
}

const allPosts = [];

for (const msgId of msgIds) {
  const startIdx = html.indexOf(`data-post="electrocentre39/${msgId}"`);
  if (startIdx === -1) continue;
  const chunk = html.substring(startIdx, startIdx + 8000);

  const textMatch = chunk.match(/class="tgme_widget_message_text[^"]*"[^>]*>([\s\S]*?)<\/div>/);
  let text = '';
  if (textMatch) {
    let raw = textMatch[1];
    raw = raw.replace(/<br\s*\/?>/gi, '\n');
    raw = raw.replace(/<[^>]+>/g, '');
    raw = raw.replace(/&amp;/g,'&').replace(/&lt;/g,'<').replace(/&gt;/g,'>').replace(/&#39;/g,"'").replace(/&quot;/g,'"');
    text = raw.trim();
  }

  const dateMatch = chunk.match(/datetime="([^"]+)"/);
  const date = dateMatch ? dateMatch[1] : '';

  const photoMatch = chunk.match(/tgme_widget_message_photo_wrap[^>]*style="[^"]*background-image:url\('([^']+)'\)/);
  const hasPhoto = !!photoMatch;
  const photoUrl = photoMatch ? photoMatch[1] : '';

  const hasVideo = chunk.includes('tgme_widget_message_video') || chunk.includes('<video');
  const videoMatch = chunk.match(/<video[^>]*\bsrc=['"]([^'"]+)['"]/i)
                  || chunk.match(/<video[^>]*\bdata-src=['"]([^'"]+)['"]/i);
  const videoUrl = videoMatch ? videoMatch[1] : '';
  const videoThumbMatch = chunk.match(/tgme_widget_message_video_thumb[^>]*style="[^"]*background-image:url\('([^']+)'\)/);
  const videoThumb = videoThumbMatch ? videoThumbMatch[1] : '';

  allPosts.push({ id: msgId, text, date, hasPhoto, photoUrl, hasVideo, videoUrl, videoThumb });
}

const photoPosts = allPosts.filter(p => p.hasPhoto).slice(-2).reverse();
const videoPosts = allPosts.filter(p => p.hasVideo).slice(-1);

const result = {
  posts: [
    ...photoPosts.slice(0,1).map(p => ({ type: 'photo', text: p.text, date: p.date, img: proxyUrl(p.photoUrl) })),
    ...photoPosts.slice(1,2).map(p => ({ type: 'photo', text: p.text, date: p.date, img: proxyUrl(p.photoUrl) })),
    ...videoPosts.map(p => ({ type: 'video', text: p.text, date: p.date, videoUrl: p.videoUrl ? proxyUrl(p.videoUrl) : '', videoThumb: proxyUrl(p.videoThumb) }))
  ],
  updatedAt: new Date().toISOString()
};

return [{ json: result }];
